import { Component, Event, h, Prop, EventEmitter, Element, State } from '@stencil/core';
import { PlusIcon, MinusIcon, ArrowIcon, SlidersHorizontalIcon, CaretCircleUpIcon } from '../../subcomponents/svg/Svg';

@Component({
  tag: 'button-component',
  styleUrl: 'button-component.css',
  shadow: true,
})
export class ButtonComponent {
  @Element() el: HTMLElement;

  @Prop() type: 'button' | 'submit' | 'reset' = 'button';
  @Prop() btndisabled: string;
  @Prop() isbtnprimary: string;
  @Prop() role: string = 'button';
  @Prop() label: string;
  @Prop() tabNumber: number = 0;
  @Prop() optionalStyles: object = {};
  @Prop() isLoading: boolean = false;
  @Prop() optionalClass: string = '';
  @Prop() isArrow: boolean = true;
  @Prop() iconType: 'arrow' | 'plus' | 'minus' | 'slidershorizontal' | 'caretcircleup' | 'none' = 'arrow';
  @Prop() iconPosition: 'left' | 'right' = 'right';
  @Prop() btnId: string = 'default-btn-id';

  @Event() btnClick: EventEmitter<MouseEvent>;
  @Event() btnKeyUp: EventEmitter<KeyboardEvent>;
  @Event() btnKeyDown: EventEmitter<KeyboardEvent>;
  @Event() btnFocus: EventEmitter<FocusEvent>;
  @Event() btnBlur: EventEmitter<FocusEvent>;
  @Event() btnMouseOver: EventEmitter<MouseEvent>;
  @Event() btnMouseOut: EventEmitter<MouseEvent>;
  @Event() btnMouseEnter: EventEmitter<MouseEvent>;
  @Event() btnMouseLeave: EventEmitter<MouseEvent>;

  @State() hasTextContent: boolean = false;

  componentWillLoad() {
    this.btndisabled = this.btndisabled || 'No';
    this.isbtnprimary = this.isbtnprimary || 'Yes';
  }

  componentDidRender() {
    // Use componentDidRender instead of componentDidLoad to ensure slotted content is fully rendered
    // Only update state if the value has changed to prevent unnecessary re-renders
    const hasText = this.el.textContent?.trim().length > 0;
    if (this.hasTextContent !== hasText) {
      this.hasTextContent = hasText;
    }
  }

  handleClick(event: MouseEvent) {
    if (this.btndisabled.toLowerCase() !== 'yes') {
      this.btnClick.emit(event);
    }
  }

  handleKeyDown(event: KeyboardEvent) {
    this.btnKeyDown.emit(event);
    if ((this.btndisabled.toLowerCase() !== 'yes' && event.key === 'Enter') || event.key === ' ') {
      event.preventDefault();
      this.btnClick.emit(new MouseEvent('click', { bubbles: true }));
    }
  }

  private renderIcon() {
    const iconClassName = 'button-icon';

    if (this.isArrow === false) {
      // Only show non-arrow icons when explicitly set
      if (this.iconType === 'plus') {
        return <PlusIcon className={iconClassName} />;
      }
      if (this.iconType === 'minus') {
        return <MinusIcon className={iconClassName} />;
      }
      if (this.iconType === 'slidershorizontal') {
        return <SlidersHorizontalIcon className={iconClassName} />;
      }

      if (this.iconType === 'caretcircleup') {
        return <CaretCircleUpIcon className={`${iconClassName} caret-circle-up-icon`} />;
      }
      // For 'none' or 'arrow' iconType, respect the isArrow=false and show nothing
      return null;
    }

    // Allow other icon types when isArrow is true
    if (this.iconType === 'plus') {
      return <PlusIcon className={iconClassName} />;
    }
    if (this.iconType === 'minus') {
      return <MinusIcon className={iconClassName} />;
    }
    if (this.iconType === 'slidershorizontal') {
      return <SlidersHorizontalIcon className={iconClassName} />;
    }
    if (this.iconType === 'caretcircleup') {
        return <CaretCircleUpIcon className={`${iconClassName} caret-circle-up-icon`} />;
    }
    if (this.iconType === 'none') {
      return null;
    }

    return <ArrowIcon className={iconClassName} />;
  }

  render() {
    const isDisabled = this.btndisabled === 'Yes' || this.isLoading;
    const isIconOnly = !this.hasTextContent && !this.isLoading;
    const buttonClass = `button_container btn ${this.isbtnprimary === 'No' ? 'secondary' : 'primary'}-button ${this.isbtnprimary === 'No' && 'secondary'} ${
      isDisabled ? 'disabled' : 'active'
    } ${isIconOnly ? 'icon-only' : ''} ${this.optionalClass}`;

    const iconElement = this.isLoading ? (
      <span class="loader"></span>
    ) : (
      this.renderIcon()
    );

    return (
      <button
        type={this.type}
        class={buttonClass}
        aria-label={this.label}
        disabled={isDisabled}
        role={this.role}
        tabindex={isDisabled ? -1 : this.tabNumber}
        ariaDisabled={isDisabled ? 'true' : null}
        ariaLabel={this.label}
        onClick={event => this.handleClick(event)}
        onFocus={event => this.btnFocus.emit(event)}
        onBlur={event => this.btnBlur.emit(event)}
        onMouseOver={event => this.btnMouseOver.emit(event)}
        onMouseOut={event => this.btnMouseOut.emit(event)}
        onMouseEnter={event => this.btnMouseEnter.emit(event)}
        onMouseLeave={event => this.btnMouseLeave.emit(event)}
        onKeyUp={event => this.btnKeyUp.emit(event)}
        onKeyDown={event => this.handleKeyDown(event)}
        style={{ ...this.optionalStyles }}
        id={this.btnId}
      >
        <span class="_button_content__bRCou">
          {this.iconPosition === 'left' && iconElement}

          {this.hasTextContent && (
            <span class="c-fs-16 c-fs-lg-20">
              <slot />
            </span>
          )}

          {this.iconPosition === 'right' && iconElement}
        </span>
      </button>
    );
  }
}
